    PSYC335:{name:"Early Experience and the Developing Infant",desc:"The period from conception to age three is marked by impressively rapid development. Neural plasticity provides both fetus and infant with an exquisite sensitivity to context. Early adversity casts a shadow on development.",term:"F",attrs:[],level:300,tags:["psychology"],prereq:null},
    PSYC338:{name:"Inquiry, Invention and Ideas",desc:"Children tinker, explore and create, but some more than others, and under some conditions more than others. What leads children to investigate, invent and build their own ideas?",term:"S",attrs:[],level:300,tags:["psychology"],prereq:"PSYC101"},
