    PSYC343:{name:"The Social Psychology of Emotion",desc:"In 1884, William James published an essay entitled \"What Is an Emotion?\" in which he called on the nascent field of psychology to look beyond the study of perception and cognition and consider,.",term:"S",attrs:[],level:300,tags:["psychology"],prereq:null},
    PSYC354:{name:"Health Psychology",desc:"This course will contrast the traditional biomedical model of health with the biopsychosocial model of health, emphasizing how biological, psychological, and sociocultural factors influence health and well-being.",term:"S",attrs:[],level:300,tags:["health","science"],prereq:null},
