    PSYC358:{name:"Developmental Psychopathology: Trajectories of Risk and Resilience",desc:"Why do some youth develop psychopathology in the face of adversity whereas others do not? How do we define psychological disorders in youth? Is resilience a static trait, or can it be promoted?",term:"F",attrs:[],level:300,tags:["psychology"],prereq:null},
    PSYC397:{name:"Independent Study: Psychology",desc:"Open to upperclass students. Requires the permission of the instructor/advisor and department. Students interested in doing an independent study should make arrangements with the appropriate professor prior to registration.",term:"F",attrs:[],level:300,tags:["gis"],prereq:null},
    PSYC398:{name:"Independent Study: Psychology",desc:"Open to upperclass students. Requires the permission of the instructor/advisor and department. Students interested in doing an independent study should make arrangements with the appropriate professor prior to registration.",term:"S",attrs:[],level:300,tags:["gis"],prereq:null},
    PSYC404:{name:"What Makes Work \"Work\"?: The Psychology of the Workplace",desc:"Why do some jobs feel energizing, while others feel completely draining? Why do some teams click, while others fall apart? Why is a \"good boss\" so rare -- and what makes a leader even worth following?",term:"F",attrs:[],level:400,tags:["psychology"],prereq:null},
    PSYC407:{name:"Success and Failure",desc:"The theme of this psychology senior seminar will be success. We will discuss the path to personal success, including the relative importance of hard work, genetic talent, and luck; barriers to.",term:"F",attrs:[],level:400,tags:["psychology"],prereq:null},
    PSYC412:{name:"Feelings & Emotions: Shaping the Brain and Society",desc:"This course will explore what emotions are, the evolutionary origins of emotions, and the tools and techniques researchers use to study emotions both in humans and in animal models.",term:"F",attrs:[],level:400,tags:["psychology"],prereq:null},
    PSYC415:{name:"Psychology of Change",desc:"What does it take to change your habits, your mind, your personality, your intelligence, or your belief system? Are there periods in the lifespan when it is easier or harder to change? Can someone become a \"new\" person?",term:"F",attrs:[],level:400,tags:["psychology"],prereq:null},
    PSYC417:{name:"What's the Point of School?",desc:"What have you gotten out of school? How do you know? What should school be for? Most children all over the world are now expected (or required) to attend school for at least 12 years.",term:"F",attrs:[],level:400,tags:["psychology"],prereq:null},
    PSYC420:{name:"Psychology of Eating",desc:"Humans need to eat for biological reasons, to fuel and nourish our bodies. However, much of eating behavior is shaped by factors beyond our biology, including our psychology and surroundings.",term:"F",attrs:[],level:400,tags:["science"],prereq:null}
