    CSCI102:{name:"The Socio-Techno Web",desc:"Tutorial examining how social networks, virtual identity, privacy, and online security connect the social and technological worlds.",term:"S",attrs:[],level:100,tags:["social computing","networks","privacy"],prereq:null},
