    CHEM321:{name:"Biochemistry I: Structure and Function of Molecules",desc:"How the molecules of life — proteins, enzymes, nucleic acids — are built and how they function.",term:"F",attrs:[],level:300,tags:["biochemistry"],prereq:"CHEM201",hardstem:true,
      cross:[{code:"BIOL321",deptKey:"biol"}]},
