    CHEM361:{name:"Quantum Chemistry and Chemical Dynamics",desc:"How quantum mechanics explains molecular structure, bonding, and reaction rates.",term:"S",attrs:[],level:300,tags:["quantum chemistry"],prereq:null,hardstem:true},
    CHEM313:{name:"Synthetic Applications in Chemistry",desc:"Interdisciplinary lab course teaching advanced synthetic and spectroscopic techniques, culminating in an independent project.",term:"F",attrs:["WS"],level:300,tags:["synthesis","spectroscopy"],prereq:"CHEM201",hardstem:true},
