function findCourseGlobal(code){
  for(const k of DEPT_ORDER){ if(DEPTS[k].courses[code]) return {deptKey:k, course:DEPTS[k].courses[code], deptObj:DEPTS[k]}; }
  for(const k in LANGUAGES){ if(LANGUAGES[k].courses[code]) return {deptKey:k, course:LANGUAGES[k].courses[code], deptObj:LANGUAGES[k]}; }
  return null;
}
function deptOf(key){ return DEPTS[key] || LANGUAGES[key]; }
